import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { login } from '../services/api';

export default function Login() {
  const { loginUser } = useAuth();
  const navigate = useNavigate();
  const [form, setForm]       = useState({ email: 'admin@school.edu', password: 'admin123' });
  const [error, setError]     = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const res = await login(form);
      loginUser(res.data.token, res.data.user);
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.message || 'Login failed. Check your credentials.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.page}>

      {/* Animated background orbs */}
      <div style={{...styles.orb, ...styles.orb1}} />
      <div style={{...styles.orb, ...styles.orb2}} />
      <div style={{...styles.orb, ...styles.orb3}} />

      <div style={styles.card}>

        {/* Back Button */}
        <button style={styles.backBtn} onClick={() => navigate(-1)}>
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none"
            stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M19 12H5M12 5l-7 7 7 7"/>
          </svg>
          Back
        </button>

        {/* Logo */}
        <div style={styles.logoRow}>
          <div style={styles.logoMark}>
            <svg width="22" height="22" viewBox="0 0 18 18" fill="none">
              <path d="M3 14V8l6-5 6 5v6H11v-4H7v4H3z" fill="white" />
            </svg>
          </div>
          <div>
            <div style={styles.logoTitle}>EduManage</div>
            <div style={styles.logoSub}>School Management System</div>
          </div>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit}>
          <div style={styles.formGroup}>
            <label style={styles.label}>Email address</label>
            <input
              style={styles.input}
              type="email"
              value={form.email}
              onChange={(e) => setForm({ ...form, email: e.target.value })}
              placeholder="admin@school.edu"
              required
            />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Password</label>
            <input
              style={styles.input}
              type="password"
              value={form.password}
              onChange={(e) => setForm({ ...form, password: e.target.value })}
              placeholder="••••••••"
              required
            />
          </div>

          {error && (
            <div style={styles.errorBox}>{error}</div>
          )}

          <button style={styles.submitBtn} type="submit" disabled={loading}>
            {loading ? 'Signing in...' : 'Sign in'}
          </button>
        </form>

        <p style={styles.demoText}>Demo: admin@school.edu / admin123</p>
      </div>

      {/* Keyframe styles */}
      <style>{`
        @keyframes floatOrb {
          0%, 100% { transform: translateY(0px) scale(1); }
          50% { transform: translateY(-20px) scale(1.05); }
        }
        @keyframes cardFloat {
          0%, 100% { transform: rotateX(3deg) translateY(0px); }
          50% { transform: rotateX(2deg) translateY(-6px); }
        }
        @keyframes logoPulse {
          0%, 100% { box-shadow: 0 0 15px rgba(108,99,255,0.4); }
          50% { box-shadow: 0 0 30px rgba(108,99,255,0.8); }
        }
        .login-back-btn:hover {
          color: #fff !important;
          transform: translateX(-3px) !important;
        }
        .login-input:focus {
          border-color: rgba(108,99,255,0.7) !important;
          background: rgba(108,99,255,0.1) !important;
          box-shadow: 0 0 0 3px rgba(108,99,255,0.2) !important;
        }
        .login-submit:hover {
          transform: translateY(-1px) !important;
          box-shadow: 0 8px 25px rgba(108,99,255,0.45) !important;
        }
      `}</style>
    </div>
  );
}

const styles = {
  page: {
    minHeight: '100vh',
    background: 'linear-gradient(135deg, #0f0c29, #302b63, #24243e)',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontFamily: 'sans-serif',
    position: 'relative',
    overflow: 'hidden',
  },
  orb: {
    position: 'absolute',
    borderRadius: '50%',
    filter: 'blur(60px)',
    opacity: 0.35,
    animation: 'floatOrb 8s ease-in-out infinite',
  },
  orb1: {
    width: 350, height: 350,
    background: '#6c63ff',
    top: -100, left: -100,
    animationDelay: '0s',
  },
  orb2: {
    width: 250, height: 250,
    background: '#00d4aa',
    bottom: -80, right: -60,
    animationDelay: '3s',
  },
  orb3: {
    width: 180, height: 180,
    background: '#ff6584',
    bottom: 80, left: 80,
    animationDelay: '1.5s',
  },
  card: {
    background: 'rgba(255,255,255,0.07)',
    backdropFilter: 'blur(20px)',
    WebkitBackdropFilter: 'blur(20px)',
    border: '1px solid rgba(255,255,255,0.15)',
    borderRadius: 20,
    padding: '36px 32px',
    width: 340,
    zIndex: 2,
    animation: 'cardFloat 6s ease-in-out infinite',
    boxShadow: '0 25px 60px rgba(0,0,0,0.4), inset 0 1px 0 rgba(255,255,255,0.15)',
  },
  backBtn: {
    display: 'flex',
    alignItems: 'center',
    gap: 6,
    background: 'none',
    border: 'none',
    color: 'rgba(255,255,255,0.6)',
    fontSize: 13,
    cursor: 'pointer',
    marginBottom: 20,
    padding: '4px 0',
    transition: 'all 0.2s',
  },
  logoRow: {
    display: 'flex',
    alignItems: 'center',
    gap: 12,
    marginBottom: 24,
  },
  logoMark: {
    width: 42, height: 42,
    background: 'linear-gradient(135deg, #6c63ff, #00d4aa)',
    borderRadius: 12,
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    animation: 'logoPulse 3s ease-in-out infinite',
  },
  logoTitle: {
    fontSize: 20,
    fontWeight: 500,
    color: '#fff',
  },
  logoSub: {
    fontSize: 12,
    color: 'rgba(255,255,255,0.5)',
    marginTop: 2,
  },
  formGroup: {
    marginBottom: 16,
  },
  label: {
    display: 'block',
    fontSize: 12,
    color: 'rgba(255,255,255,0.6)',
    marginBottom: 6,
  },
  input: {
    width: '100%',
    background: 'rgba(255,255,255,0.08)',
    border: '1px solid rgba(255,255,255,0.15)',
    borderRadius: 10,
    padding: '10px 14px',
    color: '#fff',
    fontSize: 14,
    outline: 'none',
    transition: 'all 0.25s',
    boxSizing: 'border-box',
  },
  errorBox: {
    background: 'rgba(255,80,80,0.15)',
    border: '1px solid rgba(255,80,80,0.3)',
    color: '#ff9999',
    padding: '9px 12px',
    borderRadius: 8,
    fontSize: 12,
    marginBottom: 14,
  },
  submitBtn: {
    width: '100%',
    padding: '12px',
    background: 'linear-gradient(135deg, #6c63ff, #00d4aa)',
    border: 'none',
    borderRadius: 12,
    color: '#fff',
    fontSize: 14,
    fontWeight: 500,
    cursor: 'pointer',
    transition: 'all 0.25s',
  },
  demoText: {
    textAlign: 'center',
    fontSize: 11,
    color: 'rgba(255,255,255,0.35)',
    marginTop: 16,
  },
};
